# ====================== 五行元素計算 ======================
def get_element(birth_year: int) -> Dict:
    """計算五行元素"""
    element_idx = (birth_year // 10) % 5
    return KHMER_ELEMENTS[element_idx]


class ReamkerAstrology:
    """高棉 Reamker 占星核心類別"""

    def __init__(self):
        self.characters = REAMKER_CHARACTERS
        self.zodiac = KHMER_ZODIAC
        self.prophecies = PROPHECIES
        self.directions = DIRECTIONS
        self.rama_arrows = RAMA_ARROWS

    def get_khmer_zodiac(self, birth_year: int) -> Dict:
        """計算高棉 12 生肖"""
        mod = birth_year % 12
        for z in self.zodiac:
            if z["year_mod"] == mod:
                z_with_element = z.copy()
                z_with_element["element"] = get_element(birth_year)
                return z_with_element
        return self.zodiac[0]

    def calculate_eight_influences(self, birth_year: int, gender: str = "female", 
                                    current_age: Optional[int] = None) -> Dict:
        """
        計算 Reamker 八大影響（32 格表格法）
        基於 Bizot 2013 TK480 手稿
        """
        age = current_age if current_age is not None else (datetime.now().year - birth_year)
        cell = age % 32
        
        # 性別決定數字排列順序
        if gender.lower() == "female":
            order = [1, 2, 3, 4, 5, 8, 7, 6]
        else:
            order = [7, 5, 8, 6, 1, 2, 3, 4]
        
        # 取得對應命座、階段、預言、化解儀式
        key = (gender.lower(), cell)
        if key in self.prophecies:
            char_id, stage_idx, prophecy_kh, prophecy_zh, remedy_kh, remedy_zh = self.prophecies[key]
            
            character = self.characters.get(char_id, self.characters[1])
            direction = self.directions[cell % 8]
            
            return {
                "character": character,
                "stage_kh": STAGE_KH[stage_idx],
                "stage_en": STAGE_EN[stage_idx],
                "stage_zh": STAGE_ZH[stage_idx],
                "prophecy_kh": prophecy_kh,
                "prophecy_zh": prophecy_zh,
                "remedy_kh": remedy_kh,
                "remedy_zh": remedy_zh,
                "direction": direction,
                "cell": cell,
                "age": age,
                "order": order
            }
        
        return {"error": "計算異常：找不到對應預言"}

    def calculate_rama_arrows(self, age: int) -> Dict:
        """
        計算羅摩之箭（ព្រួញព្រះរាម）
        年齡除以 9 取餘數，對應箭頭 1-9
        """
        arrow = ((age - 1) % 9) + 1
        arrow_data = self.rama_arrows.get(arrow, self.rama_arrows[1])
        
        return {
            "arrow": arrow,
            "data": arrow_data,
            "age": age
        }

    def full_reading(self, birth_year: int, gender: str, 
                     current_age: Optional[int] = None, language: str = "zh") -> Dict:
        """
        一鍵完整高棉占星報告
        """
        age = current_age if current_age is not None else (datetime.now().year - birth_year)
        
        zodiac = self.get_khmer_zodiac(birth_year)
        element = get_element(birth_year)
        eight = self.calculate_eight_influences(birth_year, gender, age)
        arrows = self.calculate_rama_arrows(age)
        
        return {
            "system": "高棉 Reamker 占星",
            "system_kh": "ហោរាសាស្ត្រ Reamker",
            "birth_year": birth_year,
            "gender": gender,
            "age": age,
            "zodiac": zodiac,
            "element": element,
            "reamker": eight,
            "rama_arrows": arrows,
            "language": language,
            "note_zh": "此為傳統數理占卜，結合佛教與史詩原型，重點在『心誠 + 儀式化解』",
            "note_kh": "នេះគឺជាការទស្សន៍ទាយតាមគណិតវិទ្យាបុរាណ រួមបញ្ចូលព្រះពុទ្ធសាសនា និងរឿងរាមកេរ្តិ៍"
        }


